return await space.current.patchWidget("snake-game", {
  edits: [
    {
      // Smooth, caterpillar-like movement by animating the rendered head/body
      // between cell positions instead of snapping instantly.
      find: /const\s+CELL_SIZE\s*=\s*\d+[\s\S]*?(?=function|class|export|const\s+gameLoop)/,
      replace: (m) => m
        .replace(
          /const\s+CELL_SIZE\s*=\s*\d+/,
          `const CELL_SIZE = 20`
        )
        + `

const MOVE_ANIMATION_MS = 120

let renderOffset = { x: 0, y: 0 }
let renderOffsetTarget = { x: 0, y: 0 }
let renderOffsetStart = { x: 0, y: 0 }
let renderOffsetStartAt = 0
let renderOffsetAnimating = false

function animateOffsetTo(targetX, targetY) {
  renderOffsetStart = { ...renderOffset }
  renderOffsetTarget = { x: targetX, y: targetY }
  renderOffsetStartAt = performance.now()
  renderOffsetAnimating = true
}

function updateRenderOffset(now = performance.now()) {
  if (!renderOffsetAnimating) return
  const t = Math.min(1, (now - renderOffsetStartAt) / MOVE_ANIMATION_MS)
  const eased = t < 1 ? 1 - Math.pow(1 - t, 3) : 1
  renderOffset.x = renderOffsetStart.x + (renderOffsetTarget.x - renderOffsetStart.x) * eased
  renderOffset.y = renderOffsetStart.y + (renderOffsetTarget.y - renderOffsetStart.y) * eased
  if (t >= 1) renderOffsetAnimating = false
}
`
    },
    {
      // Animate each step by keeping the previous snake position as the
      // starting render position and easing to the new grid position.
      find: /function\s+moveSnake\s*\([\s\S]*?\n\}/,
      replace: (m) => {
        const injected = m
          .replace(
            /const\s+newHead\s*=\s*\{\s*x:\s*head\.x\s*\+\s*dx,\s*y:\s*head\.y\s*\+\s*dy\s*\}/,
            `const oldHead = { ...head }
const newHead = { x: head.x + dx, y: head.y + dy }`
          )
          .replace(
            /snake\.unshift\(newHead\)/,
            `snake.unshift(newHead)
animateOffsetTo((oldHead.x - newHead.x) * CELL_SIZE, (oldHead.y - newHead.y) * CELL_SIZE)`
          )
        return injected
      }
    },
    {
      // Ensure animation progress updates during draw/render.
      find: /function\s+draw\s*\([\s\S]*?\n\}/,
      replace: (m) => {
        if (m.includes('updateRenderOffset')) return m
        return m.replace(
          /(\{[\s\S]*?\})\s*\n\}/,
          `$1
  updateRenderOffset()
}`
        )
      }
    },
    {
      // Apply the eased offset to snake segments when rendering.
      find: /function\s+drawSnake\s*\([\s\S]*?\n\}/,
      replace: (m) => {
        return m.replace(
          /const\s+x\s*=\s*segment\.x\s*\*\s*CELL_SIZE\s*;/,
          `const x = segment.x * CELL_SIZE + (segment === snake[0] ? renderOffset.x : 0);`
        ).replace(
          /const\s+y\s*=\s*segment\.y\s*\*\s*CELL_SIZE\s*;/,
          `const y = segment.y * CELL_SIZE + (segment === snake[0] ? renderOffset.y : 0);`
        )
      }
    }
  ]
})

